class TextEditor {

    private String text;
    private int cursor;

    public TextEditor() {
        text = "";
        cursor = 0;
    }

    public void addText(String text) {
        this.text += text;
        cursor += text.length();
    }

    public int deleteText(int k) {
        k = Math.min(k, cursor);
        cursor -= k;
        return k;
    }

    public String cursorLeft(int k) {
        k = Math.min(k, cursor);
        cursor -= k;
        return text.substring(cursor, text.length());
    }

    public String cursorRight(int k) {
        k = Math.min(k, text.length() - cursor);
        cursor += k;
        return text.substring(text.length() - cursor, text.length());
    }
}
```
